import React from 'react';
import Article from '../Article.js';
import './Featured.css';

function Featured() {

  return (
    <div className='Featured'>
      <h2><i>Featured Articles</i></h2>
      <div id='Featured'>
        <Article index={this.state.left} />
        <Article index={this.state.middle} />
        <Article index={this.state.right} />
      </div>
    </div>
  );
}

export default Featured;
